class Solution {
public:
    vector<bool> friendRequests(int n, vector<vector<int>>& restrictions, vector<vector<int>>& requests) {
        vector<bool> result(requests.size(), true);
        vector<vector<bool>> graph(n);
        for (auto& restriction : restrictions) {
            graph[restriction[0]].push_back(restriction[1]);
            graph[restriction[1]].push_back(restriction[0]);
        }
        for (int i = 0; i < requests.size(); i++) {
            int u = requests[i][0], v = requests[i][1];
            if (find(graph[u].begin(), graph[u].end(), v) != graph[u].end()) {
                result[i] = false;
            } else {
                for (auto& neighbor : graph[u]) {
                    if (find(graph[neighbor].begin(), graph[neighbor].end(), v) != graph[neighbor].end()) {
                        result[i] = false;
                        break;
                    }
                }
            }
        }
        return result;
    }
};
